balExpanded ? "arrow.up.arrow.down.circle.fill" : "arrow.up.arrow.down.circle")                            .font(.title)                            .foregroundColor(.blue)                    }                }                .padding()                .background(Color(.secondarySystemBackground))                // Scrollable List Content                ScrollView {                    VStack(alignment: .leading, spacing: 5) {                        ForEach(getTopLevelFolders()) { folder in                            FolderListView(folder: folder, userModel: userModel, globalExpanded: $globalExpanded)                        }                    }                    .padding(.horizontal)                }            }            .navigationBarHidden(true)        }    }}struct FolderListView: View {    let folder: OTDFolder    let userModel: OTDUserModel    @Binding var globalExpanded: Bool    @State private var isExpanded: Bool = true    @State private var dragOver: Bool = false    var body: some View {        DisclosureGroup(isExpanded: $isExpanded) {            VStack(spacing: 5) {                // Draggable Lists                ForEach(userModel.getMetasInFolder(for: folder)) { meta in                    NavigationLink(destination: EditListView(listModel: OTDListModel(metadata: meta), isPresented: .constant(true))                        .environmentObject(userModel)) {                        HStack {                            Text(meta.title)                                .foregroundColor(.primary)                                .font(.body)                                .padding(.leading, 10)                            Spacer()                        }                        .frame(maxWidth: .infinity)                        .padding()                        .background(Color(.secondarySystemBackground))                        .cornerRadius(8)                        .shadow(color: Color.black.opacity(0.1), radius: 2)                    }                    .padding(.horizontal, 10)                    .draggable(meta.id.uuidString) // Dragging Lists                }                // Drop Target for Lists & Folders                Rectangle()                    .fill(dragOver ? Color.blue.opacity(0.2) : Color.clear)                    .frame(height: 40)                    .onDrop(of: ["public.text"], isTargeted: $dragOver) { providers in                        handleDrop(providers: providers, targetFolder: folder)                    }                // Draggable Subfolders                ForEach(subfolders(for: folder)) { subfolder in                    FolderListView(folder: subfolder, userModel: userModel, globalExpanded: $globalExpanded)                        .padding(.leading, 16)                        .draggable(subfolder.id.uuidString) // Dragging Folders                }            }        } label: {            HStack {                Text(folder.name)                    .font(.headline)                    .foregroundColor(.primary)                Spacer()                Image(systemName: "folder.fill")                    .foregroundColor(.yellow)            }            .padding()            .background(Color(.secondarySystemBackground))            .cornerRadius(10)            .onDrop(of: ["public.text"], isTargeted: $dragOver) { providers in                handleDrop(providers: providers, targetFolder: folder)            }        }        .onChange(of: globalExpanded) { newValue in            isExpanded = newValue        }    }    func subfolders(for folder: OTDFolder) -> [OTDFolder] {        guard let allFolders = userModel.currentUser?.folders else { return [] }        return allFolders.filter { folder.folders.contains($0.id) }    }    func handleDrop(providers: [NSItemProvider], targetFolder: OTDFolder) -> Bool {        for provider in providers {            provider.loadItem(forTypeIdentifier: "public.text", options: nil) { (data, error) in                guard let data = data as? Data, let droppedItemID = String(data: data, encoding: .utf8),                      let uuid = UUID(uuidString: droppedItemID) else { return }                DispatchQueue.main.async {                    if userModel.currentUser?.lists.contains(where: { $0.id == uuid }) == true {                        moveList(withID: uuid, to: targetFolder)                    } else if userModel.currentUser?.folders.contains(where: { $0.id == uuid }) == true {                        moveFolder(withID: uuid, to: targetFolder)                    }                }            }        }        return true    }    func moveList(withID id: UUID, to targetFolder: OTDFolder) {        guard var user = userModel.currentUser else { return }        // Ensure list exists in user.lists        guard user.lists.contains(where: { $0.id == id }) else { return }        // Remove the list from any folder that contains it        for index in user.folders.indices {            user.folders[index].removeList(id)        }        // Add the list to the new folder        if let targetIndex = user.folders.firstIndex(where: { $0.id == targetFolder.id }) {            user.folders[targetIndex].addList(id)        }        userModel.currentUser = user    }    func moveFolder(withID id: UUID, to targetFolder: OTDFolder) {        guard var user = userModel.currentUser else { return }        // Ensure folder exists in user.folders        guard user.folders.contains(where: { $0.id == id }) else { return }        // Prevent circular nesting        if isDescendant(folderID: id, targetFolder: targetFolder, user: user) {            print("Error: Cannot move a folder into its own descendant.")            return        }        // Remove from previous parent folder        for index in user.folders.indices {            user.folders[index].removeFolder(id)        }        // Add folder to new parent folder        if let targetIndex = user.folders.firstIndex(where: { $0.id == targetFolder.id }) {            user.folders[targetIndex].addFolder(id)        }        userModel.currentUser = user    }    func isDescendant(folderID: UUID, targetFolder: OTDFolder, user: OTDUser) -> Bool {        var toVisit = [targetFolder]        while !toVisit.isEmpty {            let current = toVisit.removeLast()            if current.folders.contains(folderID) {                return true            }            toVisit.append(contentsOf: user.folders.filter { current.folders.contains($0.id) })        }        return false    }}